import { translate } from '@verbb/plugin-kit-react/utils/translation';

const emailRegex = /(^$|^(([^<>()[\]\\.,;:\s@"]+(\.[^<>()[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$)/;
const variableRegex = /({.*?})/;
const envRegex = /^\$(\w+)$|^\$\{(\w+)\}$/;

const isValidEmailOrVariableToken = (token: string): boolean => {
    return emailRegex.test(token) || variableRegex.test(token) || envRegex.test(token);
};

export const emailOrVariableRule = (value: unknown, label: string) => {
    const text = String(value).trim();

    if (text === '') {
        return null;
    }

    const tokens = text.split(/[\s,;]+/).filter(Boolean);
    const isValid = tokens.every(isValidEmailOrVariableToken);

    if (!isValid) {
        return translate('{attribute} must be a valid email address, environment variable, or variable.', { attribute: label });
    }

    return null;
};
